question:
以下Python代碼的輸出是什麼？

def func(a, b=1, *args, **kwargs):
    print(a, b, args, kwargs)

func(1, 2, 3, 4, x=5, y=6)

以下Python代碼的輸出是什麼？

data = {"a": 1, "b": 2}
print(data.get("c", 3))

以下Python代碼的輸出是什麼？

class A:
    def __init__(self):
        self.x = 1

    def __call__(self):
        return self.x * 2

a = A()
print(a())

以下Python代碼的輸出是什麼？

class MyClass:
    def __init__(self, value):
        self._value = value

    @property
    def value(self):
        return self._value * 2

obj = MyClass(5)
print(obj.value)
